SELECT a.id, o.goods_title AS goodsTitle, a.name, a.appointment_date, a.status, r.file_path AS filePath FROM tb_appointment a JOIN tb_order o ON a.order_id = o.id LEFT JOIN tb_checkup_report r ON a.id = r.appointment_id WHERE o.customer_id = #{customerId} AND a.is_deleted = 0
AND a.status = #{request.status}
AND a.appointment_date = #{request.appointmentDate}
AND ( o.goods_title LIKE CONCAT( "%", #{request.keyword}, "%" ) OR a.`name` = #{request.keyword} OR a.tel = #{request.keyword} )
ORDER BY a.id DESC LIMIT #{start}, #{length}

SELECT COUNT(*)
FROM tb_appointment a
INNER JOIN tb_order o ON a.order_id = o.id
WHERE o.customer_id = #{customerId}
AND a.is_deleted = 0

    AND a.status = #{request.status}


    AND a.appointment_date = #{request.appointmentDate}


    AND (
        o.goods_title LIKE CONCAT('%', #{request.keyword}, '%')
        OR a.name = #{request.keyword}
        OR a.tel = #{request.keyword}
    )

SELECT a.id, a.name, a.appointment_date, a.sex, a.tel, a.pid, a.appointment_desc as `desc`, a.status, o.goods_title AS goodsTitle, o.snapshot_id AS snapshotId FROM tb_appointment a INNER JOIN tb_order o ON a.order_id = o.id
a.is_deleted = 0
AND a.appointment_date = #{request.appointmentDate}
AND a.name LIKE CONCAT("%",#{request.name},"%")
AND a.tel = #{request.tel}
AND a.status = #{request.status}
ORDER BY a.id DESC LIMIT #{start}, #{length}

SELECT COUNT(*)
FROM tb_appointment a
